@implements IDisposable
@inject IAddressValidator AddressValidator

<h3>Shipping Information</h3>

<div class="form-group">
    <label for="name">Name</label>
    <input id="name" @bind="ShippingInfo.Name" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="address">Address</label>
    <input id="address" @bind="ShippingInfo.Address" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="city">City</label>
    <input id="city" @bind="ShippingInfo.City" disabled="@_isValidating" />
</div>

<div class="form-group">
    <label for="zip">Zip Code</label>
    <input id="zip" @bind="ShippingInfo.ZipCode" disabled="@_isValidating" />
</div>

@if (!string.IsNullOrEmpty(_validationError))
{
    <div class="validation-error">@_validationError</div>
}

<button disabled="@_isValidating" @onclick="ValidateAndProceed">
    @if (_isValidating)
    {
        <span class="spinner"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    [Parameter]
    public ShippingInfo ShippingInfo { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private bool _isValidating;
    private string? _validationError;
    private CancellationTokenSource? _cts;

    private async Task ValidateAndProceed()
    {
        // Cancel any previous in-flight validation.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _validationError = null;
        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                ShippingInfo.Address,
                ShippingInfo.City,
                ShippingInfo.ZipCode,
                token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — nothing to do.
        }
        finally
        {
            // Only clear the spinner if this is still the active validation.
            if (!token.IsCancellationRequested)
            {
                _isValidating = false;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

